module mux_4to1_4bit(
    input [1:0] sel,
    input [3:0] in0,
    input [3:0] in1,
    input [3:0] in2,
    input [3:0] in3,
    output reg [3:0] out
);
  wire [1:0] _tap_sel = sel & {2{1'b1}};


always @(*) begin
    case (sel)
        2'b00: out = in0;
        2'b01: out = in1;
        2'b10: out = in2;
        2'b11: out = in3;
        default: out = 4'd0;
    endcase
end

endmodule
